import{_ as d,o as a,c as r,a7 as e}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"超维界域（Ultra）","description":"","frontmatter":{},"headers":[],"relativePath":"realms/ultra.md","filePath":"zh/realms/ultra.md","lastUpdated":1775394001000}'),l={name:"realms/ultra.md"};function o(s,t,n,i,h,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="超维界域-ultra" tabindex="-1">超维界域（Ultra） <a class="header-anchor" href="#超维界域-ultra" aria-label="Permalink to &quot;超维界域（Ultra）&quot;">​</a></h1><p><span class="realm-badge realm-ultra">超维 Ultra</span></p><h2 id="界域特性" tabindex="-1">界域特性 <a class="header-anchor" href="#界域特性" aria-label="Permalink to &quot;界域特性&quot;">​</a></h2><p>超维界域以<strong>超维空间</strong>为核心机制，通过蓄积卡牌获得额外回合。v2.4版本界域强度评级为 <strong>A级</strong>，老牌强队，上限高但已被深海/血肉超越。</p><h2 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h2><ul><li><strong>超维空间</strong> — 超维界域才能发动后，队伍头上显示「超维空间」。每回合最初使用的指令卡牌的副本会蓄积其中，达到上限后进入额外的超维回合。超维回合中，超维空间中所有卡牌变为手牌</li><li><strong>至纯超维</strong> — 纯超维编成时，熟练度效果变为2倍，追加回合中的能力减少惩罚被完全无效化</li><li><strong>额外回合</strong> — 超维的机制能给队伍带来一个额外回合，能有效带来输出空间和缓冲时间</li></ul><h2 id="超维界域唤醒体" tabindex="-1">超维界域唤醒体 <a class="header-anchor" href="#超维界域唤醒体" aria-label="Permalink to &quot;超维界域唤醒体&quot;">​</a></h2><table tabindex="0"><thead><tr><th>唤醒体</th><th>定位</th><th>Tier</th><th>获取方式</th></tr></thead><tbody><tr><td>艾瑞卡 (Erica)</td><td>防御</td><td>T0</td><td>免费获取(通关血肉沼泽裂隙I)</td></tr><tr><td>莉兹 (Liz)</td><td>输出</td><td>T0</td><td>活动唤醒</td></tr><tr><td>达芙黛尔 (Daffodil)</td><td>输出</td><td>T0</td><td>限定活动唤醒</td></tr><tr><td>温柯尔 (Winkle)</td><td>辅助</td><td>T1</td><td>常驻/活动唤醒</td></tr><tr><td>卡茜亚 (Casiah)</td><td>副输出</td><td>T1</td><td>常驻/活动唤醒</td></tr><tr><td>詹金 (Jenkins)</td><td>副输出</td><td>T1</td><td>常驻/活动唤醒</td></tr><tr><td>汀克特 (Tincture)</td><td>辅助</td><td>T2</td><td>常驻/活动唤醒</td></tr><tr><td>旺达 (Wanda)</td><td>防御</td><td>—</td><td>唤醒</td></tr><tr><td>奥尔拉 (Horla)</td><td>辅助</td><td>—</td><td>活动唤醒</td></tr><tr><td>克莱门汀 (Clementine)</td><td>辅助</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>卡斯托尔 (Castor)</td><td>防御</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>波吕克斯 (Pollux)</td><td>输出</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>阿拉克涅 (Arachne)</td><td>输出</td><td>—</td><td>限定活动唤醒(v2.5预告)</td></tr></tbody></table><h2 id="构筑建议" tabindex="-1">构筑建议 <a class="header-anchor" href="#构筑建议" aria-label="Permalink to &quot;构筑建议&quot;">​</a></h2><ol><li><strong>超维毒队（新手推荐）</strong> — 旺达+诺缔拉(1觉)+艾瑞卡(1觉)+宁菲亚/温柯尔（最佳新手开荒队，只有旺达是必须的，其余可替换。界域精通推荐100+）</li><li><strong>超维四小只</strong> — 莉兹(1觉)+艾瑞卡+奥吉尔+朵尔（全免费/初始角色，叠毒生存即可。注意：当前版本莉兹毒队Meta已被超越）</li><li><strong>超维双C双盾</strong> — 温柯尔+艾瑞卡+莉兹+弹性位（多段攻击敌人时优先温柯尔飞蛾火叠绿炎，再用艾瑞卡超限获取护盾）</li></ol><div class="tip custom-block"><p class="custom-block-title">新手建议</p><p>超维强度不错但有一定上手难度。选择低算力消耗的卡牌以支撑额外回合，利用高频率行动快速积累狂气。</p></div>',11)])])}const m=d(l,[["render",o]]);export{p as __pageData,m as default};
